const numbersToWords=l=>{const L=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(l<0x14)return L[l];if(l<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](l/0xa)]+(l%0xa?'\x20'+L[l%0xa]:'');if(l<0x3e8){const n=Math['floor'](l/0x64),z=l%0x64;return(0x1===n?'εκατό':0x2===n?'διακόσια':0x3===n?'τριακόσια':0x4===n?'τετρακόσια':0x5===n?'πεντακόσια':0x6===n?'εξακόσια':0x7===n?'επτακόσια':0x8===n?'οκτακόσια':0x9===n?'εννιακόσια':'')+(z?'\x20'+numbersToWords(z):'');}return l<0xf4240?numbersToWords(Math['floor'](l/0x3e8))+'\x20χιλιάδες'+(l%0x3e8?'\x20'+numbersToWords(l%0x3e8):''):numbersToWords(Math['floor'](l/0xf4240))+'\x20εκατομμύρια'+(l%0xf4240?'\x20'+numbersToWords(l%0xf4240):'');},numberToText=(l,L='money')=>{const z=Math['floor'](l),W=Math['round'](0x64*(l-z));let Z=numbersToWords(z),D=W>0x0?numbersToWords(W):'';switch(L){case'money':return D?Z+'\x20ευρώ\x20και\x20'+D+'\x20λεπτά':Z+'\x20ευρώ';case'time':return D?Z+'\x20ώρες\x20και\x20'+D+'\x20λεπτά':Z+'\x20ώρες';default:return D?Z+'\x20και\x20'+D:''+Z;}};